root.sql:
select tab.* from ( /*สมาชิกที่กู้*/ select * from ( select sc_cls_confirm_data.confirm_date , '2' as rowno , sc_mem_m_ucf_member_group.member_group_no , sc_mem_m_ucf_member_group.member_group_name , '' as text_1 , 0 as count_mem , sum(sc_cls_confirm_data.data_balance) as sum_balance , ' รวมหนี้คงเหลือ' as text_2 from sc_cls_confirm_mem , sc_mem_m_membership_registered , sc_cls_confirm_data , sc_mem_m_ucf_member_group where sc_mem_m_membership_registered.membership_no = sc_cls_confirm_mem.membership_no and sc_mem_m_ucf_member_group.member_group_no = sc_cls_confirm_mem.member_group_no and sc_cls_confirm_data.confirm_date = sc_cls_confirm_mem.confirm_date and sc_cls_confirm_data.membership_no = sc_cls_confirm_mem.membership_no and sc_cls_confirm_mem.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' and sc_cls_confirm_data.data_group = 'LON' and sc_cls_confirm_data.data_balance > '0' --and sc_cls_confirm_data.confirm_date = '31/07/2023' /*WHERE*/ group by sc_cls_confirm_data.confirm_date , sc_mem_m_ucf_member_group.member_group_no , sc_mem_m_ucf_member_group.member_group_name order by sc_mem_m_ucf_member_group.member_group_no )
union
/*สมาชิกที่ไม่ได้กู้*/ select * from ( select sc_cls_confirm_data.confirm_date , '1' as rowno , sc_mem_m_ucf_member_group.member_group_no , sc_mem_m_ucf_member_group.member_group_name , 'จำนวน' as text_1 , count(distinct sc_cls_confirm_data.membership_no) as count_mem , sum(sc_cls_confirm_data.data_balance) as sum_balance , 'คน มูลค่าหุ้นทั้งหมด' as text_2 from sc_cls_confirm_mem , sc_mem_m_membership_registered , sc_cls_confirm_data , sc_mem_m_ucf_member_group where sc_mem_m_membership_registered.membership_no = sc_cls_confirm_mem.membership_no and sc_mem_m_ucf_member_group.member_group_no = sc_cls_confirm_mem.member_group_no and sc_cls_confirm_data.confirm_date = sc_cls_confirm_mem.confirm_date and sc_cls_confirm_data.membership_no = sc_cls_confirm_mem.membership_no and sc_cls_confirm_mem.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' and sc_cls_confirm_data.data_group = 'SHR' and sc_cls_confirm_data.data_balance > '0' --and sc_cls_confirm_data.confirm_date = '31/07/2023' /*WHERE*/ group by sc_cls_confirm_data.confirm_date , sc_mem_m_ucf_member_group.member_group_no , sc_mem_m_ucf_member_group.member_group_name order by sc_mem_m_ucf_member_group.member_group_no ) ) tab order by member_group_no , rowno
